select count(*) from sys_user where 1 = 1
and status = #{status}
and username like concat('%', #{keyword}, '%')

select id, username, password, real_name, role, status, violation_count_month, violation_month, booking_banned_until, phone, email, create_time, update_time from sys_user where 1 = 1
and status = #{status}
and username like concat('%', #{keyword}, '%')
order by create_time desc limit #{limit} offset #{offset}
